INSERT INTO reading_notes (
    user_id, book_title, author, isbn, reading_status, start_date, finish_date,
    rating, notes_content, tags, cover_image, page_count, current_page, reading_time,
    is_favorite, created_time, updated_time
) VALUES (
    #{userId}, #{bookTitle}, #{author}, #{isbn}, #{readingStatus}, #{startDate}, #{finishDate},
    #{rating}, #{notesContent}, #{tags}, #{coverImage}, #{pageCount}, #{currentPage}, #{readingTime},
    #{isFavorite}, #{createdTime}, #{updatedTime}
)

mapper.update:
UPDATE reading_notes
book_title = #{bookTitle}, author = #{author}, isbn = #{isbn}, reading_status = #{readingStatus}, start_date = #{startDate}, finish_date = #{finishDate}, rating = #{rating}, notes_content = #{notesContent}, tags = #{tags}, cover_image = #{coverImage}, page_count = #{pageCount}, current_page = #{currentPage}, reading_time = #{readingTime}, is_favorite = #{isFavorite}, updated_time = #{updatedTime},
WHERE id = #{id}

mapper.select:
SELECT 
    COUNT(*) as total_books,
    SUM(CASE WHEN reading_status = '已读' THEN 1 ELSE 0 END) as finished_books,
    SUM(CASE WHEN reading_status = '在读' THEN 1 ELSE 0 END) as reading_books,
    SUM(current_page) as total_pages,
    SUM(reading_time) as total_reading_time
FROM reading_notes
WHERE user_id = #{userId}
AND YEAR(created_time) = #{year}
AND MONTH(created_time) = #{month}
